import pandas as pd

# Sample data
data = {
    'sample_id': [1, 2, 3, 4, 5, 6, 7],
    'dna_sequence': ['ATGCTAGCTAGCTAA', 'GGGTCAATCATC', 'ATATATCGTAGCTA', 'ATGGGGTCATCATAA', 'TCAGTCAGTCAG', 'ATATCGCGCTAG', 'CGTATGCGTCGTA'],
    'species': ['Human', 'Human', 'Human', 'Mouse', 'Mouse', 'Zebrafish', 'Zebrafish']
}

# Create DataFrame
samples = pd.DataFrame(data)

# Define functions to check patterns
def has_start(seq):
    return int(seq.startswith('ATG'))

def has_stop(seq):
    return int(seq.endswith('TAA') or seq.endswith('TAG') or seq.endswith('TGA'))

def has_atat(seq):
    return int('ATAT' in seq)

def has_ggg(seq):
    return int(any(seq[i:i+3] == 'GGG' for i in range(len(seq) - 2)))

# Apply functions to the DataFrame
samples['has_start'] = samples['dna_sequence'].apply(has_start)
samples['has_stop'] = samples['dna_sequence'].apply(has_stop)
samples['has_atat'] = samples['dna_sequence'].apply(has_atat)
samples['has_ggg'] = samples['dna_sequence'].apply(has_ggg)

# Select relevant columns and sort by sample_id
result = samples[['sample_id', 'dna_sequence', 'species', 'has_start', 'has_stop', 'has_atat', 'has_ggg']].sort_values(by='sample_id')

# Display the result
print(result)
